async acquire(cost = 1, timeoutMs = 0): Promise<boolean> {
  const startTime = this.clock()

  while (true) {
    try {
      this.consume(cost)
      return true
    } catch (error) {
      if (!(error instanceof RateLimiterExceededError)) {
        throw error
      }

      const elapsed = this.clock() - startTime
      const waitNeeded = error.retryAfterMs

      if (elapsed + waitNeeded > timeoutMs) {
        return false
      }

      // Wait for the minimum of: time needed to refill, or remaining timeout
      const waitTime = Math.min(waitNeeded, timeoutMs - elapsed)
      await new Promise(resolve => setTimeout(resolve, waitTime))
    }
  }
}
```

**Key points:**

1. **Loop until success or timeout**: Repeatedly attempt to consume tokens
2. **Catch RateLimiterExceededError**: Extract the recommended retry delay
3. **Check timeout**: If `elapsed + waitNeeded > timeoutMs`, return false immediately
4. **Sleep and retry**: Wait for the lesser of the needed refill time or remaining timeout budget, then loop
5. **Return true on success**: When `consume()` succeeds without throwing

This approach is efficient because it uses the error's `retryAfterMs` hint rather than polling, and respects the timeout constraint.

